];

// 3. Block private IP ranges
function isPrivateIP(hostname) {
    const privateRanges = [
        /^10\./,
        /^172\.(1[6-9]|2[0-9]|3[0-1])\./,
        /^192\.168\./,
        /^127\./,
        /^localhost$/
    ];
    return privateRanges.some(range => range.test(hostname));
}

